import React, { useState } from 'react';
import { EditorTool } from '../types';
import { SparklesIcon, EraserIcon, MaximizeIcon, ImageIcon, WandIcon } from './Icons';

interface SidebarProps {
  activeTool: EditorTool;
  onToolChange: (tool: EditorTool) => void;
  onGenerate: (prompt: string) => void;
  onEdit: (instruction: string) => void;
  onErase: (description: string) => void;
  onUpscale: () => void;
  onRemoveBG: () => void;
  isProcessing: boolean;
  hasImage: boolean;
}

const Sidebar: React.FC<SidebarProps> = ({
  activeTool,
  onToolChange,
  onGenerate,
  onEdit,
  onErase,
  onUpscale,
  onRemoveBG,
  isProcessing,
  hasImage
}) => {
  const [prompt, setPrompt] = useState('');

  const tools = [
    { id: EditorTool.GENERATE, icon: SparklesIcon, label: 'Generate' },
    { id: EditorTool.EDIT, icon: WandIcon, label: 'Edit' },
    { id: EditorTool.ERASE, icon: EraserIcon, label: 'Erase Object' },
    { id: EditorTool.UPSCALE, icon: MaximizeIcon, label: 'Upscale' },
    { id: EditorTool.REMOVE_BG, icon: ImageIcon, label: 'Remove BG' },
  ];

  const handleAction = () => {
    if (activeTool === EditorTool.GENERATE) onGenerate(prompt);
    if (activeTool === EditorTool.EDIT) onEdit(prompt);
    if (activeTool === EditorTool.ERASE) onErase(prompt);
    if (activeTool === EditorTool.UPSCALE) onUpscale();
    if (activeTool === EditorTool.REMOVE_BG) onRemoveBG();
  };

  return (
    <div className="w-80 bg-zinc-900 border-r border-zinc-800 flex flex-col h-full">
      <div className="p-6 border-b border-zinc-800">
        <h1 className="text-xl font-bold bg-gradient-to-r from-purple-400 to-blue-500 bg-clip-text text-transparent">
          Lumina AI Studio
        </h1>
        <p className="text-zinc-500 text-sm mt-1">Professional Creative AI</p>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-2">
        {tools.map((tool) => (
          <button
            key={tool.id}
            onClick={() => onToolChange(tool.id)}
            disabled={!hasImage && tool.id !== EditorTool.GENERATE}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-all ${
              activeTool === tool.id
                ? 'bg-zinc-800 text-white border border-zinc-700 shadow-lg'
                : 'text-zinc-400 hover:bg-zinc-800/50 hover:text-zinc-200'
            } ${(!hasImage && tool.id !== EditorTool.GENERATE) ? 'opacity-50 cursor-not-allowed' : ''}`}
          >
            <tool.icon />
            <span className="font-medium">{tool.label}</span>
          </button>
        ))}
      </div>

      <div className="p-6 border-t border-zinc-800 bg-zinc-900/50">
        {(activeTool === EditorTool.GENERATE || activeTool === EditorTool.EDIT || activeTool === EditorTool.ERASE) ? (
          <div className="space-y-4">
            <label className="text-xs font-semibold text-zinc-500 uppercase tracking-wider">
              {activeTool === EditorTool.GENERATE ? 'Imagine something...' : 
               activeTool === EditorTool.ERASE ? 'Describe object to erase' : 'What should change?'}
            </label>
            <textarea
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
              placeholder={
                activeTool === EditorTool.GENERATE ? "A cinematic portrait of a cyberpunk explorer..." : 
                activeTool === EditorTool.ERASE ? "The red car in the background" : "Change the sky to sunset..."
              }
              className="w-full h-32 bg-zinc-800 border border-zinc-700 rounded-xl p-3 text-sm focus:ring-2 focus:ring-purple-500 focus:border-transparent outline-none resize-none transition-all placeholder:text-zinc-600"
            />
          </div>
        ) : (
          <div className="space-y-4 py-4">
            <p className="text-sm text-zinc-400">
              {activeTool === EditorTool.UPSCALE ? "Instantly enhance resolution and details using advanced AI." : 
               "Remove the background with surgical precision while keeping the subject."}
            </p>
          </div>
        )}

        <button
          onClick={handleAction}
          disabled={isProcessing || (!prompt && (activeTool === EditorTool.GENERATE || activeTool === EditorTool.EDIT || activeTool === EditorTool.ERASE))}
          className={`w-full mt-6 py-3 px-4 rounded-xl font-semibold flex items-center justify-center space-x-2 transition-all ${
            isProcessing 
              ? 'bg-zinc-800 text-zinc-500 cursor-not-allowed' 
              : 'bg-gradient-to-r from-purple-600 to-blue-600 hover:from-purple-500 hover:to-blue-500 text-white shadow-lg shadow-purple-500/20 active:scale-95'
          }`}
        >
          {isProcessing ? 'Processing...' : 'Apply AI Action'}
        </button>
      </div>
    </div>
  );
};

export default Sidebar;

import React, { useState, useCallback, useRef } from 'react';
import Sidebar from './components/Sidebar';
import { EditorTool, ImageHistory } from './types';
import { generateImage, editImage, upscaleImage, removeBackground, eraseObject } from './services/geminiService';
import { UploadIcon, DownloadIcon, LoaderIcon } from './components/Icons';

const App: React.FC = () => {
  const [currentImage, setCurrentImage] = useState<string | null>(null);
  const [history, setHistory] = useState<ImageHistory[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [activeTool, setActiveTool] = useState<EditorTool>(EditorTool.GENERATE);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const addImageToHistory = useCallback((url: string, prompt?: string) => {
    const newItem: ImageHistory = {
      id: Math.random().toString(36).substr(2, 9),
      url,
      prompt,
      timestamp: Date.now()
    };
    setHistory(prev => [newItem, ...prev].slice(0, 10));
    setCurrentImage(url);
  }, []);

  const handleGenerate = async (prompt: string) => {
    setIsProcessing(true);
    const result = await generateImage(prompt);
    if (result) addImageToHistory(result, prompt);
    setIsProcessing(false);
  };

  const handleEdit = async (instruction: string) => {
    if (!currentImage) return;
    setIsProcessing(true);
    const result = await editImage(currentImage, instruction);
    if (result) addImageToHistory(result, instruction);
    setIsProcessing(false);
  };

  const handleErase = async (description: string) => {
    if (!currentImage) return;
    setIsProcessing(true);
    const result = await eraseObject(currentImage, description);
    if (result) addImageToHistory(result, `Erased ${description}`);
    setIsProcessing(false);
  };

  const handleUpscale = async () => {
    if (!currentImage) return;
    setIsProcessing(true);
    const result = await upscaleImage(currentImage);
    if (result) addImageToHistory(result, 'AI Upscale');
    setIsProcessing(false);
  };

  const handleRemoveBG = async () => {
    if (!currentImage) return;
    setIsProcessing(true);
    const result = await removeBackground(currentImage);
    if (result) addImageToHistory(result, 'Background Removed');
    setIsProcessing(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const result = event.target?.result as string;
        addImageToHistory(result, 'Uploaded Image');
      };
      reader.readAsDataURL(file);
    }
  };

  const handleDownload = () => {
    if (!currentImage) return;
    const link = document.createElement('a');
    link.href = currentImage;
    link.download = `lumina-ai-edit-${Date.now()}.png`;
    link.click();
  };

  return (
    <div className="flex h-screen bg-black overflow-hidden">
      <Sidebar
        activeTool={activeTool}
        onToolChange={setActiveTool}
        onGenerate={handleGenerate}
        onEdit={handleEdit}
        onErase={handleErase}
        onUpscale={handleUpscale}
        onRemoveBG={handleRemoveBG}
        isProcessing={isProcessing}
        hasImage={!!currentImage}
      />

      <main className="flex-1 flex flex-col relative bg-zinc-950 canvas-bg">
        {/* Header Bar */}
        <div className="h-16 border-b border-zinc-900 bg-zinc-950/80 backdrop-blur-md flex items-center justify-between px-6 z-10">
          <div className="flex items-center space-x-4">
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="flex items-center space-x-2 px-4 py-2 bg-zinc-900 hover:bg-zinc-800 border border-zinc-800 rounded-lg text-sm transition-all"
            >
              <UploadIcon />
              <span>Upload Image</span>
            </button>
            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              onChange={handleFileUpload} 
              accept="image/*" 
            />
          </div>

          <div className="flex items-center space-x-4">
            {currentImage && (
              <button 
                onClick={handleDownload}
                className="flex items-center space-x-2 px-4 py-2 bg-zinc-900 hover:bg-zinc-800 border border-zinc-800 rounded-lg text-sm transition-all"
              >
                <DownloadIcon />
                <span>Download Result</span>
              </button>
            )}
          </div>
        </div>

        {/* Main Canvas Area */}
        <div className="flex-1 flex items-center justify-center p-8 relative">
          {isProcessing && (
            <div className="absolute inset-0 z-20 flex items-center justify-center bg-black/40 backdrop-blur-[2px]">
              <div className="bg-zinc-900/90 p-8 rounded-3xl border border-zinc-800 shadow-2xl flex flex-col items-center space-y-4">
                <div className="relative">
                   <div className="absolute inset-0 bg-purple-500/20 blur-xl rounded-full"></div>
                   <LoaderIcon />
                </div>
                <div className="text-center">
                  <p className="text-white font-medium">Processing Image...</p>
                  <p className="text-zinc-500 text-xs mt-1">Our AI is working its magic</p>
                </div>
              </div>
            </div>
          )}

          {currentImage ? (
            <div className="relative group max-w-full max-h-full">
              <img 
                src={currentImage} 
                alt="Edited" 
                className="max-w-full max-h-[75vh] object-contain rounded-xl shadow-2xl border border-zinc-800 transition-transform duration-500"
              />
              <div className="absolute -bottom-12 left-1/2 -translate-x-1/2 px-4 py-2 bg-zinc-900/80 backdrop-blur-md border border-zinc-800 rounded-full text-xs text-zinc-400">
                Res: {currentImage.length > 1000000 ? 'Enhanced' : 'Standard'}
              </div>
            </div>
          ) : (
            <div 
              onClick={() => fileInputRef.current?.click()}
              className="flex flex-col items-center justify-center space-y-4 p-12 border-2 border-dashed border-zinc-800 rounded-3xl hover:border-zinc-700 hover:bg-zinc-900/50 transition-all cursor-pointer group"
            >
              <div className="w-16 h-16 bg-zinc-900 rounded-2xl flex items-center justify-center group-hover:scale-110 transition-transform">
                <UploadIcon />
              </div>
              <div className="text-center">
                <p className="text-zinc-300 font-medium">Start your masterpiece</p>
                <p className="text-zinc-500 text-sm">Upload an image or use the sidebar to generate one</p>
              </div>
            </div>
          )}
        </div>

        {/* History / Versions Bar */}
        <div className="h-24 border-t border-zinc-900 bg-zinc-950 flex items-center px-6 space-x-4 overflow-x-auto">
          <div className="flex-none text-xs font-semibold text-zinc-500 uppercase tracking-widest mr-4">History</div>
          <div className="flex space-x-3">
            {history.map((item) => (
              <button
                key={item.id}
                onClick={() => setCurrentImage(item.url)}
                className={`flex-none w-16 h-16 rounded-lg border-2 overflow-hidden transition-all ${
                  currentImage === item.url ? 'border-purple-500 scale-110' : 'border-zinc-800 opacity-60 hover:opacity-100'
                }`}
              >
                <img src={item.url} alt="History step" className="w-full h-full object-cover" />
              </button>
            ))}
            {history.length === 0 && (
              <div className="flex items-center space-x-2 text-zinc-600 italic text-sm">
                No history yet...
              </div>
            )}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

