              />
              <div className="absolute -bottom-10 left-1/2 -translate-x-1/2 px-4 py-2 bg-zinc-900/80 backdrop-blur-md border border-zinc-800 rounded-full text-[10px] text-zinc-400 font-mono uppercase tracking-widest">
                AI Processed Stage
              </div>
            </div>
          ) : (
            <div 
