        <div className="h-28 border-t border-zinc-900 bg-zinc-950 flex items-center px-6 space-x-6 overflow-x-auto">
          <div className="flex-none">
            <div className="text-[10px] font-bold text-zinc-600 uppercase tracking-[0.2em] mb-2">History</div>
            <div className="h-1 w-8 bg-purple-500/50 rounded-full"></div>
          </div>
          <div className="flex space-x-4 pb-2">
            {history.map((item) => (
              <button
                key={item.id}
                onClick={() => setCurrentImage(item.url)}
                className={`flex-none w-16 h-16 rounded-xl border-2 overflow-hidden transition-all duration-300 relative group ${
                  currentImage === item.url ? 'border-purple-500 ring-4 ring-purple-500/10 scale-105' : 'border-zinc-800 opacity-50 hover:opacity-100 hover:scale-105'
                }`}
              >
