              <button 
                onClick={handleDownload}
                className="flex items-center space-x-2 px-4 py-2 bg-zinc-900 hover:bg-zinc-800 border border-zinc-800 rounded-lg text-sm transition-all text-zinc-300"
              >
                <DownloadIcon />
                <span>Download Result</span>
